BEGIN;

-- Seed villages from CSV data
ON CONFLICT (id) DO UPDATE SET
  label_english = EXCLUDED.label_english,
  mandal_id = EXCLUDED.mandal_id,
  updated_at = EXCLUDED.updated_at;

-- Seed Telugu labels as i18n entries for villages
ON CONFLICT (entity_table, entity_id, field, language_code) DO UPDATE SET
  text = EXCLUDED.text,
  updated_at = EXCLUDED.updated_at;

COMMIT;

